static lv_obj_t *create_action_button(
    lv_obj_t *parent,
    const char *text,
    lv_coord_t width,
    bool primary,
    lv_obj_t **label_out)
{
    lv_obj_t *btn = lv_btn_create(parent);
    lv_obj_set_size(btn, width, 44);
    lv_obj_clear_flag(btn, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_set_style_radius(btn, 15, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_border_width(btn, 1, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_shadow_width(btn, 0, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_pad_left(btn, 18, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_pad_right(btn, 18, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_pad_top(btn, 10, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_pad_bottom(btn, 10, LV_PART_MAIN | LV_STATE_DEFAULT);

    if (primary) {
        lv_obj_set_style_bg_color(btn, lv_color_hex(SCREEN1_COLOR_ACCENT), LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_bg_opa(btn, LV_OPA_COVER, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_border_color(btn, lv_color_hex(SCREEN1_COLOR_ACCENT), LV_PART_MAIN | LV_STATE_DEFAULT);
    } else {
        lv_obj_set_style_bg_color(btn, lv_color_hex(SCREEN1_COLOR_PANEL_ALT), LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_bg_opa(btn, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_border_color(btn, lv_color_hex(SCREEN1_COLOR_BORDER_STRONG), LV_PART_MAIN | LV_STATE_DEFAULT);
    }

    lv_obj_t *lbl = lv_label_create(btn);
    lv_label_set_text(lbl, text);
    lv_obj_set_style_text_font(lbl, &ui_font_Roboto16, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_color(
        lbl,
        lv_color_hex(SCREEN1_COLOR_TEXT),
        LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_center(lbl);

    if (label_out) {
        *label_out = lbl;
    }

    return btn;
}

