static void set_setup_local_status(const char *status_text, bool is_error)
{
    if (!status_text || status_text[0] == '\0') {
        s_setup_local_status[0] = '\0';
        s_setup_local_status_is_error = false;
        return;
    }

    strncpy(s_setup_local_status, status_text, sizeof(s_setup_local_status) - 1);
    s_setup_local_status[sizeof(s_setup_local_status) - 1] = '\0';
    s_setup_local_status_is_error = is_error;
}

static bool setup_has_wifi_activity(void)
{
    return s_scan_in_progress || s_connect_in_progress;
}

static bool setup_phase_is_transitional(config_portal_phase_t phase)
{
    return phase == CONFIG_PORTAL_PHASE_STARTING ||
           phase == CONFIG_PORTAL_PHASE_APPLYING ||
           phase == CONFIG_PORTAL_PHASE_STOPPING;
}

static void setup_transition_request(bool enable)
{
    setup_transition_result_t *job = NULL;
    const char *task_name = enable ? "screen1_setup_start" : "screen1_setup_stop";

    if (s_portal_action_busy) {
        return;
    }

    job = calloc(1, sizeof(setup_transition_result_t));
    if (!job) {
        if (enable) {
            s_setup_should_auto_open = false;
        }
        set_setup_local_status(
            enable ? screen1_text("Unable to allocate setup task", "启动设置任务失败")
                   : screen1_text("Unable to close setup right now", "当前不可关闭设置"),
            true);
        return;
    }

    job->enable = enable;
    s_portal_action_busy = true;
    set_setup_local_status(NULL, false);

    if (create_screen1_worker_task(setup_transition_task, task_name, 4096, job, tskIDLE_PRIORITY + 1) != pdPASS) {
        s_portal_action_busy = false;
        if (enable) {
            s_setup_should_auto_open = false;
        }
        set_setup_local_status(
            enable ? screen1_text("Unable to start setup. Leave this section and open it again.", "启动设置失败, 关闭此页后重试")
                   : screen1_text("Unable to close setup right now", "当前不可关闭设置"),
            true);
        free(job);
    }
}

static void maybe_process_setup_runtime_state(void)
{
    config_portal_phase_t phase = config_portal_get_phase();
    bool runtime_running = config_portal_is_runtime_mode();

    if (s_portal_action_busy) {
        return;
    }

    if (runtime_running || phase == CONFIG_PORTAL_PHASE_APPLYING || phase == CONFIG_PORTAL_PHASE_STOPPING) {
        s_setup_should_auto_open = false;
    }

    if (s_setup_should_close) {
        if (runtime_running || setup_phase_is_transitional(phase)) {
            setup_transition_request(false);
            return;
        }

        s_setup_should_close = false;
        s_setup_should_auto_open = false;
    }

    if (s_active_section == SCREEN1_SECTION_SETUP) {
        if (s_setup_should_auto_open && !runtime_running) {
            if (setup_phase_is_transitional(phase) || setup_has_wifi_activity()) {
                return;
            }

            s_setup_should_auto_open = false;
            setup_transition_request(true);
        }
        return;
    }

    s_setup_should_auto_open = false;

    if (!runtime_running) {
        return;
    }

    if (phase == CONFIG_PORTAL_PHASE_APPLYING || phase == CONFIG_PORTAL_PHASE_STOPPING) {
        return;
    }

    setup_transition_request(false);
}

static void setup_transition_task(void *arg)
{
    setup_transition_result_t *result = (setup_transition_result_t *)arg;

    if (!result) {
        delete_screen1_worker_task();
        return;
    }

    result->err = result->enable ? config_portal_start_runtime() : config_portal_stop_runtime();

    if (!ui_screen1_dispatch_async(setup_transition_done_async, result)) {
        s_portal_action_busy = false;
        free(result);
        maybe_process_setup_runtime_state();
    }

    delete_screen1_worker_task();
}

static void setup_transition_done_async(void *arg)
{
    setup_transition_result_t *result = (setup_transition_result_t *)arg;
    bool stopped_setup = false;
    bool stop_effectively_finished = false;

    s_portal_action_busy = false;

    if (result) {
        stopped_setup = !result->enable;
        stop_effectively_finished =
            stopped_setup &&
            (result->err == ESP_OK ||
             (!config_portal_is_runtime_mode() && config_portal_get_phase() == CONFIG_PORTAL_PHASE_IDLE));

        if (result->err == ESP_OK || stop_effectively_finished) {
            set_setup_local_status(NULL, false);
        } else {
            char status_text[96];
            snprintf(status_text,
                     sizeof(status_text),
                     "%s failed: %s",
                     result->enable ? screen1_text("Starting setup", "正在启动设置")
                                    : screen1_text("Closing setup", "正在关闭设置"),
                     esp_err_to_name(result->err));
            set_setup_local_status(status_text, true);
        }

        if (stop_effectively_finished) {
            s_setup_should_close = false;
            s_setup_should_auto_open = false;
        }
        free(result);
    } else {
        set_setup_local_status(screen1_text("Setup action failed", "设置操作失败"), true);
    }

    maybe_process_setup_runtime_state();

    if (ui_Screen1 &&
        stop_effectively_finished &&
        s_active_section == SCREEN1_SECTION_WIFI &&
        !s_cached_scan_results &&
        !s_scan_in_progress &&
        !config_portal_is_runtime_mode()) {
        start_wifi_scan_task();
    }

    if (s_active_section == SCREEN1_SECTION_SETUP) {
        update_setup_page_ui(NULL, false, s_portal_action_busy);
    }
}

static void setup_status_timer_cb(lv_timer_t *timer)
{
    LV_UNUSED(timer);

    maybe_process_setup_runtime_state();

    if (s_active_section == SCREEN1_SECTION_SETUP) {
        update_setup_page_ui(NULL, false, s_portal_action_busy);
    }
}

static void update_setup_qr_frame(lv_obj_t *frame, const char *payload, const char *fallback_text)
{
    if (!frame) {
        return;
    }

    lv_obj_clean(frame);

#if LV_USE_QRCODE
    if (payload && payload[0] != '\0') {
        lv_obj_t *qr = lv_qrcode_create(frame, 110, lv_color_hex(SCREEN1_COLOR_PANEL_DEEP), lv_color_hex(0xFFFFFF));
        if (lv_qrcode_update(qr, payload, strlen(payload)) == LV_RES_OK) {
            lv_obj_center(qr);
            return;
        }
        lv_obj_del(qr);
    }
#endif

    lv_obj_t *label = lv_label_create(frame);
    lv_label_set_text(label, fallback_text ? fallback_text : screen1_text("QR unavailable", "二维码暂不可用"));
    lv_label_set_long_mode(label, LV_LABEL_LONG_WRAP);
    lv_obj_set_width(label, 104);
    lv_obj_set_style_text_font(label, &ui_font_Roboto14, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_color(label, lv_color_hex(SCREEN1_COLOR_MUTED_SOFT), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_align(label, LV_TEXT_ALIGN_CENTER, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_center(label);
}

static void set_label_text_if_needed(lv_obj_t *label, const char *text)
{
    const char *next_text = text ? text : "";
    const char *current_text;

    if (!label) {
        return;
    }

    current_text = lv_label_get_text(label);
    if (current_text && strcmp(current_text, next_text) == 0) {
        return;
    }

    lv_label_set_text(label, next_text);
}

static void set_text_color_if_needed(lv_obj_t *obj, lv_color_t color)
{
    lv_color_t current_color;

    if (!obj) {
        return;
    }

    current_color = lv_obj_get_style_text_color(obj, LV_PART_MAIN | LV_STATE_DEFAULT);
    if (memcmp(&current_color, &color, sizeof(lv_color_t)) == 0) {
        return;
    }

    lv_obj_set_style_text_color(obj, color, LV_PART_MAIN | LV_STATE_DEFAULT);
}

static void set_hidden_if_needed(lv_obj_t *obj, bool hidden)
{
    bool is_hidden;

    if (!obj) {
        return;
    }

    is_hidden = lv_obj_has_flag(obj, LV_OBJ_FLAG_HIDDEN);
    if (is_hidden == hidden) {
        return;
    }

    if (hidden) {
        lv_obj_add_flag(obj, LV_OBJ_FLAG_HIDDEN);
    } else {
        lv_obj_clear_flag(obj, LV_OBJ_FLAG_HIDDEN);
    }
}

static void update_setup_qr_tiles(bool force)
{
    char wifi_qr_payload[128] = {0};
    char url_qr_payload[64] = {0};
    char step1_detail[160];
    char step2_detail[96];
    const char *ap_url = config_portal_get_ap_url();
    const char *ap_host = ap_url;
    const bool requires_setup_wifi = config_portal_requires_setup_wifi();
    const char *network_name = config_portal_get_network_name();
    const char *wifi_title = requires_setup_wifi ? screen1_text("Join the setup Wi-Fi", "连接到设置Wi-Fi")
                                                 : screen1_text("Stay on your current Wi-Fi", "使用当前Wi-Fi");
    const char *url_title = requires_setup_wifi ? screen1_text("Open the setup page", "打开设置页")
                                                : screen1_text("Open the local setup page", "打开本地设置页");

    if (!s_setup_wifi_detail_label || !s_setup_url_detail_label || !s_setup_wifi_title_label || !s_setup_url_title_label) {
        return;
    }

    if (strncmp(ap_host, "http://", 7) == 0) {
        ap_host += 7;
    }

    snprintf(url_qr_payload, sizeof(url_qr_payload), "%s", ap_url);
    snprintf(step2_detail, sizeof(step2_detail), "%s: %s", screen1_text("Open", "打开"), ap_host);

    if (requires_setup_wifi) {
        snprintf(
            wifi_qr_payload,
            sizeof(wifi_qr_payload),
            "WIFI:T:WPA;S:%s;P:%s;;",
            config_portal_get_ap_ssid(),
            config_portal_get_ap_password());
        snprintf(step1_detail,
                 sizeof(step1_detail),
                 "Wi-Fi: %s\n%s: %s",
                 config_portal_get_ap_ssid(),
                 screen1_text("Password", "密码"),
                 config_portal_get_ap_password());
    } else if (network_name && network_name[0] != '\0') {
        snprintf(step1_detail, sizeof(step1_detail), "%s:\n%s", screen1_text("Stay connected to", "连接到"), network_name);
    } else {
        snprintf(step1_detail, sizeof(step1_detail), "%s", screen1_text("Keep your phone on the same Wi-Fi as the board.", "请让手机使用当前Wi-Fi"));
    }

    set_label_text_if_needed(s_setup_wifi_title_label, wifi_title);
    set_label_text_if_needed(s_setup_url_title_label, url_title);
    set_hidden_if_needed(s_setup_wifi_qr_frame, !requires_setup_wifi);

    if (force || strcmp(s_setup_last_wifi_detail, step1_detail) != 0) {
        lv_label_set_text(s_setup_wifi_detail_label, step1_detail);
        strncpy(s_setup_last_wifi_detail, step1_detail, sizeof(s_setup_last_wifi_detail) - 1);
        s_setup_last_wifi_detail[sizeof(s_setup_last_wifi_detail) - 1] = '\0';
    }

    if (force || strcmp(s_setup_last_url_detail, step2_detail) != 0) {
        lv_label_set_text(s_setup_url_detail_label, step2_detail);
        strncpy(s_setup_last_url_detail, step2_detail, sizeof(s_setup_last_url_detail) - 1);
        s_setup_last_url_detail[sizeof(s_setup_last_url_detail) - 1] = '\0';
    }

    if (force || strcmp(s_setup_last_wifi_qr_payload, wifi_qr_payload) != 0) {
        update_setup_qr_frame(
            s_setup_wifi_qr_frame,
            wifi_qr_payload,
            screen1_text("Use the same\nWi-Fi", "使用当前\nWi-Fi"));
        strncpy(s_setup_last_wifi_qr_payload, wifi_qr_payload, sizeof(s_setup_last_wifi_qr_payload) - 1);
        s_setup_last_wifi_qr_payload[sizeof(s_setup_last_wifi_qr_payload) - 1] = '\0';
    }

    if (force || strcmp(s_setup_last_url_qr_payload, url_qr_payload) != 0) {
        update_setup_qr_frame(s_setup_url_qr_frame, url_qr_payload, screen1_text("QR unavailable", "二维码暂不可用"));
        strncpy(s_setup_last_url_qr_payload, url_qr_payload, sizeof(s_setup_last_url_qr_payload) - 1);
        s_setup_last_url_qr_payload[sizeof(s_setup_last_url_qr_payload) - 1] = '\0';
    }
}

