static void update_name_page_ui(const char *status_text, bool is_error)
{
    bool neutral = status_text && strcmp(status_text, screen1_text("Save room name", "保存会议室名称")) == 0;

    if (s_name_preview_value) {
        lv_label_set_text(s_name_preview_value, device_name_store_get());
    }

    if (s_name_textarea && !is_error) {
        lv_textarea_set_text(s_name_textarea, device_name_store_get());
        lv_textarea_set_cursor_pos(s_name_textarea, LV_TEXTAREA_CURSOR_LAST);
    }

    if (s_name_status_label) {
        lv_label_set_text(s_name_status_label, status_text ? status_text : "");
        lv_obj_set_style_text_color(
            s_name_status_label,
            lv_color_hex(is_error ? 0xFFB38A : (neutral ? SCREEN1_COLOR_MUTED : SCREEN1_COLOR_ACCENT)),
            LV_PART_MAIN | LV_STATE_DEFAULT);
    }
}

static void show_name_keyboard(bool show)
{
    if (!s_name_keyboard) {
        return;
    }

    if (show) {
        lv_obj_align(s_name_keyboard, LV_ALIGN_BOTTOM_MID, 0, 0);
        lv_obj_clear_flag(s_name_keyboard, LV_OBJ_FLAG_HIDDEN);
        lv_obj_move_foreground(s_name_keyboard);
    } else {
        lv_obj_add_flag(s_name_keyboard, LV_OBJ_FLAG_HIDDEN);
    }
}

static bool save_device_name_from_ui(void)
{
    if (!s_name_textarea) {
        return false;
    }

    esp_err_t err = device_name_store_set(lv_textarea_get_text(s_name_textarea));
    if (err != ESP_OK) {
        update_name_page_ui(screen1_text("Unable to save room name", "保存会议室名称失败"), true);
        return false;
    }

    if (ui_Screen8) {
        ui_Screen8_refresh_device_name();
    }

    update_name_page_ui(screen1_text("Room name saved", "会议室名称已保存"), false);
    show_name_keyboard(false);
    lv_obj_clear_state(s_name_textarea, LV_STATE_FOCUSED);
    return true;
}

static void name_save_button_event_cb(lv_event_t *e)
{
    if (lv_event_get_code(e) != LV_EVENT_CLICKED) {
        return;
    }

    save_device_name_from_ui();
}

static void name_keyboard_event_cb(lv_event_t *e)
{
    lv_obj_t *keyboard = lv_event_get_target(e);
    if (lv_event_get_code(e) != LV_EVENT_VALUE_CHANGED || !keyboard || !s_name_textarea) {
        return;
    }

    uint16_t btn_id = lv_keyboard_get_selected_btn(keyboard);
    if (btn_id == LV_BTNMATRIX_BTN_NONE) {
        return;
    }

    const char *txt = lv_keyboard_get_btn_text(keyboard, btn_id);
    if (!txt) {
        return;
    }

    if (strcmp(txt, "abc") == 0) {
        lv_keyboard_set_mode(keyboard, LV_KEYBOARD_MODE_TEXT_LOWER);
        return;
    }
    if (strcmp(txt, "ABC") == 0) {
        lv_keyboard_set_mode(keyboard, LV_KEYBOARD_MODE_TEXT_UPPER);
        return;
    }
    if (strcmp(txt, "1#") == 0) {
        lv_keyboard_set_mode(keyboard, LV_KEYBOARD_MODE_SPECIAL);
        return;
    }
    if (strcmp(txt, "Close") == 0) {
        update_name_page_ui(screen1_text("Changes reverted", "已撤销当前名称"), false);
        lv_keyboard_set_mode(keyboard, LV_KEYBOARD_MODE_TEXT_LOWER);
        show_name_keyboard(false);
        lv_obj_clear_state(s_name_textarea, LV_STATE_FOCUSED);
        return;
    }
    if (strcmp(txt, "OK") == 0 || strcmp(txt, "Enter") == 0) {
        save_device_name_from_ui();
        return;
    }
    if (strcmp(txt, "Del") == 0) {
        lv_textarea_del_char(s_name_textarea);
        return;
    }
    if (strcmp(txt, "Left") == 0) {
        lv_textarea_cursor_left(s_name_textarea);
        return;
    }
    if (strcmp(txt, "Right") == 0) {
        lv_textarea_cursor_right(s_name_textarea);
        return;
    }
    if (strcmp(txt, "Space") == 0) {
        lv_textarea_add_char(s_name_textarea, ' ');
        return;
    }

    lv_textarea_add_text(s_name_textarea, txt);
}

static void name_textarea_event_cb(lv_event_t *e)
{
    lv_event_code_t code = lv_event_get_code(e);
    if (!s_name_textarea) {
        return;
    }

    if (code == LV_EVENT_CLICKED || code == LV_EVENT_FOCUSED) {
        show_name_keyboard(true);
        lv_keyboard_set_textarea(s_name_keyboard, s_name_textarea);
    } else if (code == LV_EVENT_DEFOCUSED) {
        show_name_keyboard(false);
    }
}

