static void available_network_btn_event_cb(lv_event_t *e)
{
    if (lv_event_get_code(e) != LV_EVENT_CLICKED) {
        return;
    }

    lv_obj_t *btn = lv_event_get_target(e);
    if (!btn) {
        return;
    }

    lv_obj_t *lbl = lv_obj_get_child(btn, 0);
    if (!lbl) {
        return;
    }

    const char *text = lv_label_get_text(lbl);
    if (!text || text[0] == '\0') {
        return;
    }

    const char *newline = strchr(text, '\n');
    size_t len = newline ? (size_t)(newline - text) : strlen(text);
    if (len == 0) {
        return;
    }
    if (len > 32) {
        len = 32;
    }

    char ssid[33];
    memcpy(ssid, text, len);
    ssid[len] = '\0';

    destroy_networks_popup();
    show_connect_popup(ssid);
}

