static void popup_close_cb(lv_event_t *e)
{
    popup_ctx_t *ctx = (popup_ctx_t *)lv_event_get_user_data(e);
    if (!ctx || !s_popup_ctx || ctx != s_popup_ctx) {
        return;
    }

    if (ctx->connecting) {
        lv_label_set_text(ctx->status, screen1_text("Connection is in progress...", "正在连接..."));
        return;
    }

    destroy_connect_popup(true);
}

static void popup_cancel_cb(lv_event_t *e)
{
    popup_close_cb(e);
}

static bool start_popup_connect(popup_ctx_t *ctx)
{
    if (!ctx || !ctx->textarea || ctx->connecting) {
        return false;
    }

    char *ssid_copy = strdup(ctx->ssid ? ctx->ssid : "");
    char *pass_copy = strdup(lv_textarea_get_text(ctx->textarea));
    if (!ssid_copy || !pass_copy) {
        if (ssid_copy) {
            free(ssid_copy);
        }
        if (pass_copy) {
            free(pass_copy);
        }
        lv_label_set_text(ctx->status, screen1_text("Not enough memory", "空间不足"));
        return false;
    }

    connect_job_t *job = calloc(1, sizeof(connect_job_t));
    if (!job) {
        free(ssid_copy);
        free(pass_copy);
        lv_label_set_text(ctx->status, screen1_text("Not enough memory", "空间不足"));
        return false;
    }

    job->ssid = ssid_copy;
    job->password = pass_copy;

    ctx->connecting = true;
    s_connect_in_progress = true;
    lv_label_set_text(ctx->status, screen1_text("Connecting...", "正在连接..."));
    lv_obj_add_state(ctx->btn_connect, LV_STATE_DISABLED);
    lv_obj_add_state(ctx->btn_cancel, LV_STATE_DISABLED);
    lv_obj_add_state(ctx->btn_close, LV_STATE_DISABLED);

    if (create_screen1_worker_task(connect_task, "screen1_wifi_connect", 4096, job, tskIDLE_PRIORITY + 2) != pdPASS) {
        ctx->connecting = false;
        s_connect_in_progress = false;
        lv_label_set_text(ctx->status, screen1_text("Unable to start connection", "启动连接失败"));
        lv_obj_clear_state(ctx->btn_connect, LV_STATE_DISABLED);
        lv_obj_clear_state(ctx->btn_cancel, LV_STATE_DISABLED);
        lv_obj_clear_state(ctx->btn_close, LV_STATE_DISABLED);
        free(job->ssid);
        free(job->password);
        free(job);
        return false;
    }

    return true;
}

static void connect_button_event_cb(lv_event_t *e)
{
    popup_ctx_t *ctx = (popup_ctx_t *)lv_event_get_user_data(e);
    start_popup_connect(ctx);
}

static void popup_keyboard_event_cb(lv_event_t *e)
{
    if (lv_event_get_code(e) != LV_EVENT_VALUE_CHANGED || !s_popup_keyboard || !s_popup_ctx || !s_popup_ctx->textarea) {
        return;
    }

    uint16_t btn_id = lv_keyboard_get_selected_btn(s_popup_keyboard);
    if (btn_id == LV_BTNMATRIX_BTN_NONE) {
        return;
    }

    const char *txt = lv_keyboard_get_btn_text(s_popup_keyboard, btn_id);
    if (!txt) {
        return;
    }

    if (strcmp(txt, "abc") == 0) {
        lv_keyboard_set_mode(s_popup_keyboard, LV_KEYBOARD_MODE_TEXT_LOWER);
        return;
    }
    if (strcmp(txt, "ABC") == 0) {
        lv_keyboard_set_mode(s_popup_keyboard, LV_KEYBOARD_MODE_TEXT_UPPER);
        return;
    }
    if (strcmp(txt, "1#") == 0) {
        lv_keyboard_set_mode(s_popup_keyboard, LV_KEYBOARD_MODE_SPECIAL);
        return;
    }
    if (strcmp(txt, "Close") == 0) {
        if (s_popup_ctx->connecting) {
            lv_label_set_text(s_popup_ctx->status, screen1_text("Connection is in progress...", "正在连接..."));
        } else {
            destroy_connect_popup(true);
        }
        return;
    }
    if (strcmp(txt, "OK") == 0 || strcmp(txt, "Enter") == 0) {
        start_popup_connect(s_popup_ctx);
        return;
    }
    if (strcmp(txt, "Del") == 0) {
        lv_textarea_del_char(s_popup_ctx->textarea);
        return;
    }
    if (strcmp(txt, "Left") == 0) {
        lv_textarea_cursor_left(s_popup_ctx->textarea);
        return;
    }
    if (strcmp(txt, "Right") == 0) {
        lv_textarea_cursor_right(s_popup_ctx->textarea);
        return;
    }
    if (strcmp(txt, "Space") == 0) {
        lv_textarea_add_char(s_popup_ctx->textarea, ' ');
        return;
    }

    lv_textarea_add_text(s_popup_ctx->textarea, txt);
}

static void connect_task(void *arg)
{
    connect_job_t *job = (connect_job_t *)arg;
    if (!job) {
        s_connect_in_progress = false;
        delete_screen1_worker_task();
        return;
    }

    esp_err_t err = wifi_manager_init_sta(job->ssid, job->password ? job->password : "");
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "wifi_manager_init_sta(connect) -> %s", esp_err_to_name(err));
    }

    bool ok = false;
    for (int waited = 0; waited < 10000; waited += 250) {
        if (wifi_manager_is_connected()) {
            ok = true;
            break;
        }
        vTaskDelay(pdMS_TO_TICKS(250));
    }

    connect_result_t *result = calloc(1, sizeof(connect_result_t));
    if (!result) {
        s_connect_in_progress = false;
        if (job->ssid) {
            free(job->ssid);
        }
        if (job->password) {
            memset(job->password, 0, strlen(job->password));
            free(job->password);
        }
        free(job);
        delete_screen1_worker_task();
        return;
    }

    result->job = job;
    result->ok = ok;

    if (!ui_screen1_dispatch_async(connect_result_async, result)) {
        s_connect_in_progress = false;
        if (job->ssid) {
            free(job->ssid);
        }
        if (job->password) {
            memset(job->password, 0, strlen(job->password));
            free(job->password);
        }
        free(job);
        free(result);
    }

    delete_screen1_worker_task();
}

static void connect_result_async(void *arg)
{
    connect_result_t *result = (connect_result_t *)arg;
    if (!result) {
        return;
    }

    s_connect_in_progress = false;

    if (result->ok && result->job && result->job->ssid) {
        esp_err_t save_err =
            wifi_manager_save_credentials(result->job->ssid, result->job->password ? result->job->password : "");
        if (save_err != ESP_OK) {
            ESP_LOGW(TAG, "wifi_manager_save_credentials(connect) -> %s", esp_err_to_name(save_err));
        }
    }

    if (s_popup_ctx) {
        s_popup_ctx->connecting = false;
        lv_obj_clear_state(s_popup_ctx->btn_connect, LV_STATE_DISABLED);
        lv_obj_clear_state(s_popup_ctx->btn_cancel, LV_STATE_DISABLED);
        lv_obj_clear_state(s_popup_ctx->btn_close, LV_STATE_DISABLED);

        if (result->ok) {
            destroy_connect_popup(true);
        } else if (s_popup_ctx && s_popup_ctx->status) {
            lv_label_set_text(s_popup_ctx->status, screen1_text("Connection failed", "连接失败"));
        }
    }

    if (result->ok) {
        refresh_current_network_async(NULL);
    }

    if (result->job) {
        if (result->job->ssid) {
            free(result->job->ssid);
        }
        if (result->job->password) {
            memset(result->job->password, 0, strlen(result->job->password));
            free(result->job->password);
        }
        free(result->job);
    }
    free(result);
}

static void populate_available_networks(screen1_scan_results_t *results)
{
    if (!s_available_list) {
        update_available_networks_summary(results);
        return;
    }

    lv_obj_clean(s_available_list);
    update_available_networks_summary(results);

    wifi_ap_record_t *dedup = NULL;
    uint16_t kept = build_dedup_networks(results, &dedup);
    if (kept == 0) {
        lv_obj_t *empty = create_networks_list_item(s_available_list, screen1_text("No networks found", "没有找到网络"));
        if (empty) {
            lv_obj_add_state(empty, LV_STATE_DISABLED);
        }
        update_networks_pager(0, screen1_text("No networks", "没有网络"));
        free(dedup);
        return;
    }

    uint16_t page_count = (uint16_t)((kept + SCREEN1_NETWORKS_PER_PAGE - 1) / SCREEN1_NETWORKS_PER_PAGE);
    if (page_count == 0) {
        page_count = 1;
    }
    if (s_networks_page >= page_count) {
        s_networks_page = page_count - 1;
    }

    uint16_t start = (uint16_t)(s_networks_page * SCREEN1_NETWORKS_PER_PAGE);
    uint16_t end = start + SCREEN1_NETWORKS_PER_PAGE;
    if (end > kept) {
        end = kept;
    }

    for (uint16_t i = start; i < end; ++i) {
        lv_obj_t *btn = create_networks_list_item(s_available_list, (const char *)dedup[i].ssid);
        if (!btn) {
            continue;
        }
        lv_obj_add_event_cb(btn, available_network_btn_event_cb, LV_EVENT_CLICKED, NULL);

        char rssi_text[20];
        snprintf(rssi_text, sizeof(rssi_text), "%ddBm", dedup[i].rssi);

        lv_obj_t *rssi_lbl = lv_label_create(btn);
        lv_label_set_text(rssi_lbl, rssi_text);
        lv_obj_add_flag(rssi_lbl, LV_OBJ_FLAG_EVENT_BUBBLE);
        lv_obj_set_style_text_font(rssi_lbl, &ui_font_Roboto14, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_color(rssi_lbl, lv_color_hex(SCREEN1_COLOR_MUTED), LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_clear_flag(rssi_lbl, LV_OBJ_FLAG_CLICKABLE);
    }

    update_networks_pager(kept, NULL);
    free(dedup);
}

static void refresh_current_network_async(void *arg)
{
    LV_UNUSED(arg);

    wifi_ap_record_t current_ap = {0};
    bool has_current = false;

    if (wifi_manager_is_connected() && wifi_manager_lock(250)) {
        has_current = (esp_wifi_sta_get_ap_info(&current_ap) == ESP_OK);
        wifi_manager_unlock();
    }

    if (has_current) {
        update_current_network_ui(true, &current_ap);
    } else {
        update_current_network_ui(false, NULL);
    }
}

static void apply_scan_results_async(void *arg)
{
    screen1_scan_results_t *results = (screen1_scan_results_t *)arg;

    if (!ui_Screen1) {
        free_scan_results(results);
        s_scan_in_progress = false;
        return;
    }

    if (results && results->has_current) {
        update_current_network_ui(true, &results->current_ap);
    } else {
        refresh_current_network_async(NULL);
    }

    s_scan_in_progress = false;
    replace_cached_scan_results(results);
    update_available_networks_preview(results, NULL);
    populate_available_networks(results);
    update_scan_button_state(false);
    free_scan_results(results);
}

static void wifi_scan_task(void *arg)
{
    LV_UNUSED(arg);

    bool wifi_locked = wifi_manager_lock(15000);
    if (!wifi_locked) {
        ESP_LOGW(TAG, "wifi_scan_task: failed to obtain Wi-Fi lock");
        s_scan_in_progress = false;
        delete_screen1_worker_task();
        return;
    }

    esp_err_t err = wifi_manager_init_sta(NULL, NULL);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "wifi_manager_init_sta(NULL) -> %s", esp_err_to_name(err));
        wifi_manager_unlock();
        s_scan_in_progress = false;
        delete_screen1_worker_task();
        return;
    }

    err = esp_wifi_set_mode(WIFI_MODE_STA);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "esp_wifi_set_mode(WIFI_MODE_STA) -> %s", esp_err_to_name(err));
    }

    err = esp_wifi_start();
    if (err != ESP_OK && err != ESP_ERR_WIFI_STATE) {
        ESP_LOGW(TAG, "esp_wifi_start -> %s", esp_err_to_name(err));
    }

    vTaskDelay(pdMS_TO_TICKS(200));
    err = esp_wifi_set_ps(WIFI_PS_NONE);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "esp_wifi_set_ps(WIFI_PS_NONE) -> %s", esp_err_to_name(err));
    }

    wifi_scan_config_t scan_cfg = {0};
    scan_cfg.scan_type = WIFI_SCAN_TYPE_ACTIVE;
    scan_cfg.show_hidden = false;

    bool disconnected_for_scan = false;
    if (!wifi_manager_is_connected()) {
        err = esp_wifi_disconnect();
        if (err == ESP_OK) {
            disconnected_for_scan = true;
            vTaskDelay(pdMS_TO_TICKS(150));
        }
    }

    wifi_ap_record_t *records = NULL;
    uint16_t found = 0;
    wifi_ap_record_t current_ap = {0};
    bool has_current = false;

    for (int attempt = 0; attempt < 3; ++attempt) {
        err = esp_wifi_scan_start(&scan_cfg, true);
        if (err == ESP_OK) {
            uint16_t ap_num = 0;
            if (esp_wifi_scan_get_ap_num(&ap_num) == ESP_OK && ap_num > 0) {
                records = calloc(ap_num, sizeof(wifi_ap_record_t));
                if (!records) {
                    break;
                }

                if (esp_wifi_scan_get_ap_records(&ap_num, records) == ESP_OK) {
                    found = ap_num;
                    break;
                }

                free(records);
                records = NULL;
            }
        } else if (err == ESP_ERR_WIFI_STATE && !wifi_manager_is_connected()) {
            esp_wifi_disconnect();
            disconnected_for_scan = true;
        } else {
            ESP_LOGW(TAG, "esp_wifi_scan_start attempt %d -> %s", attempt + 1, esp_err_to_name(err));
        }

        vTaskDelay(pdMS_TO_TICKS(220));
    }

    if (disconnected_for_scan) {
        vTaskDelay(pdMS_TO_TICKS(150));
        esp_wifi_connect();
    }

    if (wifi_manager_is_connected() && esp_wifi_sta_get_ap_info(&current_ap) == ESP_OK) {
        has_current = true;
    }

    wifi_manager_unlock();

    screen1_scan_results_t *results = calloc(1, sizeof(screen1_scan_results_t));
    if (!results) {
        if (records) {
            free(records);
        }
        s_scan_in_progress = false;
        delete_screen1_worker_task();
        return;
    }

    results->records = records;
    results->num = found;
    if (has_current) {
        results->current_ap = current_ap;
        results->has_current = true;
    }

    if (!ui_screen1_dispatch_async(apply_scan_results_async, results)) {
        free_scan_results(results);
        s_scan_in_progress = false;
    }

    delete_screen1_worker_task();
}

static void start_wifi_scan_task(void)
{
    config_portal_phase_t portal_phase = config_portal_get_phase();

    if (s_scan_in_progress) {
        return;
    }

    if (config_portal_is_runtime_mode() ||
        portal_phase == CONFIG_PORTAL_PHASE_STARTING ||
        portal_phase == CONFIG_PORTAL_PHASE_APPLYING ||
        portal_phase == CONFIG_PORTAL_PHASE_STOPPING) {
        if (s_available_summary_label) {
            lv_label_set_text(s_available_summary_label, screen1_text("Scanning is unavailable while Setup is active", "设置激活时不可扫描"));
        }
        update_available_networks_preview(NULL, screen1_text("Close Setup to scan nearby networks", "关闭设置后扫描附近网络"));
        return;
    }

    uint32_t free_int = (uint32_t)heap_caps_get_free_size(MALLOC_CAP_INTERNAL);
    uint32_t largest_int = (uint32_t)heap_caps_get_largest_free_block(MALLOC_CAP_INTERNAL);
    if (free_int < 2048 || largest_int < 1024) {
        ESP_LOGW(TAG,
                 "Skipping Wi-Fi scan: low INTERNAL heap (free=%u, largest=%u)",
                 (unsigned)free_int,
                 (unsigned)largest_int);
        show_scan_idle_placeholder();
        update_scan_button_state(false);
        return;
    }

    s_scan_in_progress = true;
    s_networks_page = 0;
    update_scan_button_state(true);
    show_scanning_placeholder();

    if (create_screen1_worker_task(wifi_scan_task, "screen1_wifi_scan", 4096, NULL, tskIDLE_PRIORITY + 1) != pdPASS) {
        s_scan_in_progress = false;
        update_scan_button_state(false);
        populate_available_networks(NULL);
    }
}

static void scan_button_event_cb(lv_event_t *e)
{
    if (lv_event_get_code(e) != LV_EVENT_CLICKED) {
        return;
    }

    start_wifi_scan_task();
}

static void disconnect_button_event_cb(lv_event_t *e)
{
    if (lv_event_get_code(e) != LV_EVENT_CLICKED) {
        return;
    }

    if (s_disconnect_btn) {
        lv_obj_add_state(s_disconnect_btn, LV_STATE_DISABLED);
    }
    if (s_disconnect_btn_label) {
        lv_label_set_text(s_disconnect_btn_label, screen1_text("Forgetting...", "正在忘记..."));
    }

    wifi_manager_disconnect(true);
    update_current_network_ui(false, NULL);
    update_available_networks_summary(s_cached_scan_results);
}

static void back_button_event_cb(lv_event_t *e)
{
    if (lv_event_get_code(e) != LV_EVENT_CLICKED) {
        return;
    }

    s_setup_should_auto_open = false;
    s_setup_should_close = true;
    show_name_keyboard(false);
    maybe_process_setup_runtime_state();
    _ui_screen_change(&ui_Screen8, LV_SCR_LOAD_ANIM_NONE, 0, 0, &ui_Screen8_screen_init);
}

static void screen1_wifi_event_handler(void *arg, esp_event_base_t event_base, int32_t event_id, void *event_data)
{
    LV_UNUSED(arg);
    LV_UNUSED(event_data);

    if (!ui_Screen1) {
        return;
    }

    if ((event_base == IP_EVENT && event_id == IP_EVENT_STA_GOT_IP) ||
        (event_base == WIFI_EVENT && event_id == WIFI_EVENT_STA_CONNECTED) ||
        (event_base == WIFI_EVENT && event_id == WIFI_EVENT_STA_DISCONNECTED)) {
        ui_screen1_dispatch_async(refresh_current_network_async, NULL);
    }
}

