        esp_event_handler_unregister(IP_EVENT, IP_EVENT_STA_GOT_IP, &screen1_wifi_event_handler);
        esp_event_handler_unregister(WIFI_EVENT, WIFI_EVENT_STA_CONNECTED, &screen1_wifi_event_handler);
